import React, { useState, useEffect } from 'react';
import './App.css';
import { 
  Container, 
  Typography, 
  Box, 
  Button, 
  Paper,
  Grid,
  IconButton,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  TextField,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Stack
} from '@mui/material';
import { 
  Add as AddIcon, 
  Delete as DeleteIcon,
  CalendarMonth as CalendarIcon,
  ViewList as ListIcon,
  ViewModule as GridIcon
} from '@mui/icons-material';
import { AdapterDateFns } from '@mui/x-date-pickers/AdapterDateFns';
import { LocalizationProvider, DatePicker } from '@mui/x-date-pickers';
import { format, isSameMonth } from 'date-fns';

function App() {
  const [events, setEvents] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [currentDate, setCurrentDate] = useState(new Date());
  const [viewType, setViewType] = useState('month');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [studentId, setStudentId] = useState("");
  const [formData, setFormData] = useState({
    eventType: '',
    date: new Date(),
    description: ''
  });

  const eventTypes = {
    'class': { name: 'Class', color: '#4CAF50' },
    'study': { name: 'Study', color: '#2196F3' },
    'exercise': { name: 'Exercise', color: '#FF9800' },
    'other': { name: 'Other', color: '#9C27B0' }
  };

  useEffect(() => {
    const savedStudentId = localStorage.getItem('studentId');
    if (savedStudentId) {
      setStudentId(savedStudentId);
      setIsLoggedIn(true);
      const savedEvents = localStorage.getItem(`events_${savedStudentId}`);
      if (savedEvents) {
        setEvents(JSON.parse(savedEvents));
      }
    }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      localStorage.setItem(`events_${studentId}`, JSON.stringify(events));
    }
  }, [events, studentId, isLoggedIn]);

  const handleLogin = () => {
    if (!studentId) {
      alert('Please enter your Student ID');
      return;
    }
    localStorage.setItem('studentId', studentId);
    setIsLoggedIn(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('studentId');
    setIsLoggedIn(false);
    setStudentId('');
    setEvents([]);
  };

  const handleAddEvent = () => {
    if (!formData.eventType) {
      alert('Please fill in all required fields');
      return;
    }

    const newEvent = {
      id: Date.now(),
      ...formData,
      studentId,
      date: formData.date.toISOString()
    };

    setEvents([...events, newEvent]);
    setShowForm(false);
    setFormData({
      eventType: '',
      date: new Date(),
      description: ''
    });
  };

  const handleDeleteEvent = (eventId) => {
    setEvents(events.filter(event => event.id !== eventId));
  };

  const handleDateChange = (date) => {
    setCurrentDate(date);
  };

  const handleViewChange = (type) => {
    setViewType(type);
  };

  const filteredEvents = events.filter(event => {
    const eventDate = new Date(event.date);
    if (viewType === 'month') {
      return isSameMonth(eventDate, currentDate);
    }
    return true;
  });

  if (!isLoggedIn) {
    return (
      <Container maxWidth="sm">
        <Box sx={{ 
          my: 4,
          minHeight: '100vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          backgroundColor: '#f5f5f5'
        }}>
          <Paper sx={{ p: 4, textAlign: 'center', width: '100%', maxWidth: 400 }}>
            <Typography variant="h4" component="h1" gutterBottom sx={{ color: '#355E3B' }}>
              P.A.S.E Daily Tracker
            </Typography>
            <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4 }}>
              Please log in with your Student ID
            </Typography>
            <TextField
              fullWidth
              label="Student ID"
              value={studentId}
              onChange={(e) => setStudentId(e.target.value)}
              sx={{ mb: 2 }}
            />
            <Button 
              variant="contained" 
              onClick={handleLogin} 
              fullWidth
              sx={{ 
                backgroundColor: '#355E3B',
                '&:hover': {
                  backgroundColor: '#2a4a2f'
                }
              }}
            >
              Login
            </Button>
          </Paper>
        </Box>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg">
      <Box sx={{ my: 4 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 4 }}>
          <Box sx={{ flexGrow: 1 }}>
            <Typography variant="h4" component="h1" gutterBottom>
              P.A.S.E Daily Tracker
            </Typography>
            <Typography variant="subtitle1" color="text.secondary">
              Student ID: {studentId}
            </Typography>
          </Box>
          <Box sx={{ display: 'flex', gap: 2 }}>
            <Button variant="outlined" onClick={handleLogout}>
              Logout
            </Button>
            <Button
              variant="contained"
              startIcon={<AddIcon />}
              onClick={() => setShowForm(true)}
            >
              Add Event
            </Button>
          </Box>
        </Box>

        <Paper sx={{ p: 2, mb: 3 }}>
          <Grid container spacing={2} alignItems="center">
            <Grid item xs={12} md={4}>
              <LocalizationProvider dateAdapter={AdapterDateFns}>
                <DatePicker
                  label="Select Date"
                  value={currentDate}
                  onChange={handleDateChange}
                  slotProps={{ textField: { fullWidth: true } }}
                />
              </LocalizationProvider>
            </Grid>
            <Grid item xs={12} md={8}>
              <Box sx={{ display: 'flex', gap: 2, justifyContent: 'flex-end' }}>
                <Button
                  variant={viewType === 'month' ? 'contained' : 'outlined'}
                  startIcon={<CalendarIcon />}
                  onClick={() => handleViewChange('month')}
                >
                  Month
                </Button>
                <Button
                  variant={viewType === 'list' ? 'contained' : 'outlined'}
                  startIcon={<ListIcon />}
                  onClick={() => handleViewChange('list')}
                >
                  List
                </Button>
                <Button
                  variant={viewType === 'grid' ? 'contained' : 'outlined'}
                  startIcon={<GridIcon />}
                  onClick={() => handleViewChange('grid')}
                >
                  Grid
                </Button>
              </Box>
            </Grid>
          </Grid>
        </Paper>

        <Box sx={{ mt: 2 }}>
          <Grid container spacing={2}>
            {filteredEvents.map(event => (
              <Grid item xs={12} sm={6} md={4} key={event.id}>
                <Paper 
                  sx={{ 
                    p: 2,
                    borderLeft: `4px solid ${eventTypes[event.eventType].color}`
                  }}
                >
                  <Typography variant="h6">{eventTypes[event.eventType].name}</Typography>
                  <Typography variant="body2">
                    {format(new Date(event.date), 'PPpp')}
                  </Typography>
                  {event.description && (
                    <Typography variant="body2">{event.description}</Typography>
                  )}
                  <IconButton 
                    onClick={() => handleDeleteEvent(event.id)}
                    color="error"
                    size="small"
                    sx={{ mt: 1 }}
                  >
                    <DeleteIcon />
                  </IconButton>
                </Paper>
              </Grid>
            ))}
          </Grid>
        </Box>

        <Dialog
          open={showForm}
          onClose={() => setShowForm(false)}
          maxWidth="sm"
          fullWidth
          keepMounted
          disablePortal
        >
          <DialogTitle>Add New Event</DialogTitle>
          <DialogContent>
            <Stack spacing={3} sx={{ mt: 2 }}>
              <FormControl fullWidth required>
                <InputLabel>Event Type</InputLabel>
                <Select
                  value={formData.eventType}
                  label="Event Type"
                  onChange={(e) => setFormData({ ...formData, eventType: e.target.value })}
                >
                  {Object.entries(eventTypes).map(([key, value]) => (
                    <MenuItem key={key} value={key}>
                      {value.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
              <LocalizationProvider dateAdapter={AdapterDateFns}>
                <DatePicker
                  label="Date & Time"
                  value={formData.date}
                  onChange={(newValue) => setFormData({ ...formData, date: newValue })}
                  renderInput={(params) => <TextField {...params} fullWidth />}
                />
              </LocalizationProvider>
              <TextField
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                fullWidth
                multiline
                rows={4}
              />
            </Stack>
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setShowForm(false)}>Cancel</Button>
            <Button onClick={handleAddEvent} variant="contained">
              Add Event
            </Button>
          </DialogActions>
        </Dialog>
      </Box>
    </Container>
  );
}

export default App; 